// D-0024-M fixture-only classifier outputs. Change selectedFixture to run one case.
const selectedFixture = 'all';

const eventBase = {
  event_id: '<EVENT_ID>',
  source_repo: '<REPO>',
  source_commit: '<COMMIT_SHA>',
  source_workflow: '<WORKFLOW_ID>',
  tailnet_host: '<RYZEN>.<TAILNET>.ts.net',
  ryzen_ts_ip: '<RYZEN_TS_IP>',
  vps_ts_ip: '<VPS_TS_IP>',
  summary: 'fixture-only Decision Packet mapping preview (D-0024-M)'
};

const fixtures = [
  {
    fixture_id: 'human_gate',
    classifier_output: {
      risk: 'medium',
      route: 'human_gate',
      reason: 'fixture:runtime_adjacent_manual_review_required',
      confidence: 'high',
      requires_human: true
    }
  },
  {
    fixture_id: 'auto_allowed',
    classifier_output: {
      risk: 'low',
      route: 'auto_allowed',
      reason: 'fixture:docs_only_low_risk',
      confidence: 'high',
      requires_human: false
    }
  },
  {
    fixture_id: 'blocked',
    classifier_output: {
      risk: 'high',
      route: 'blocked',
      reason: 'fixture:blocked_explicit_override_required',
      confidence: 'high',
      requires_human: true
    }
  },
  {
    fixture_id: 'fail_closed',
    classifier_output: {
      risk: 'low',
      route: 'invalid_route_not_in_schema',
      reason: null
    }
  }
];

const picked = selectedFixture === 'all'
  ? fixtures
  : fixtures.filter((f) => f.fixture_id === selectedFixture);

return picked.map((f) => ({
  json: {
    fixture_id: f.fixture_id,
    selectedFixture,
    classifier_output: f.classifier_output,
    event_context: { ...eventBase, fixture_id: f.fixture_id },
    fixture_only: true,
    test_only: true,
    no_runtime: true
  }
}));

// Build Decision Packet preview per docs/contracts/decision-packet-mapping-v1.md
const ALLOWED_ROUTES = ['auto_allowed', 'human_gate', 'blocked'];
const ALLOWED_RISK = ['low', 'medium', 'high'];
const ALLOWED_CONF = ['low', 'medium', 'high'];

function isValidClassifier(c) {
  if (!c || typeof c !== 'object' || Array.isArray(c)) return false;
  const req = ['risk', 'route', 'reason', 'confidence', 'requires_human'];
  for (const k of req) {
    if (!Object.prototype.hasOwnProperty.call(c, k)) return false;
  }
  if (!ALLOWED_ROUTES.includes(String(c.route))) return false;
  if (!ALLOWED_RISK.includes(String(c.risk))) return false;
  if (!ALLOWED_CONF.includes(String(c.confidence))) return false;
  if (typeof c.reason !== 'string' || c.reason.length === 0) return false;
  if (typeof c.requires_human !== 'boolean') return false;
  return true;
}

function failClosed(reason) {
  return {
    risk: 'high',
    route: 'human_gate',
    requires_human: true,
    confidence: 'low',
    reason: reason || 'fallback:malformed_or_incoherent_fixture'
  };
}

function buildOptions() {
  return [
    '1 — Do not proceed; keep manual mode',
    '2 — Review manually and decide the next bounded step',
    '3 — Authorize a supervised, scope-limited next step'
  ];
}

function recommendationFor(route) {
  if (route === 'blocked') {
    return 'Raccomandazione: 1 — Do not proceed; keep manual mode unless explicit override context exists.';
  }
  return 'Raccomandazione: 2 — Review manually and decide the next bounded step.';
}

function perché(route, c) {
  if (route === 'blocked') {
    return 'Classifier route is blocked — do not proceed without explicit human override.';
  }
  if (c.confidence === 'low') {
    return 'Classifier confidence is low — fail-closed human review required.';
  }
  return 'Classifier requires human gate — no silent auto-proceed for this event context.';
}

function buildPacket(c, eventCtx, fixtureId) {
  const provenance = [
    'event_id=' + eventCtx.event_id,
    'repo=' + eventCtx.source_repo,
    'commit=' + eventCtx.source_commit,
    'source=' + eventCtx.source_workflow,
    'fixture=' + fixtureId
  ].join('; ');
  return {
    ID: 'D-0024-M-T',
    Kind: 'runtime',
    Contesto: 'Fixture "' + fixtureId + '": ' + eventCtx.summary + ' Classifier route ' + c.route + '; risk ' + c.risk + '.',
    'Perché serve decisione': perché(c.route, c),
    Opzioni: buildOptions(),
    Raccomandazione: recommendationFor(c.route),
    'Rischio principale': 'Proceeding without human boundary check may expand scope or touch forbidden runtime despite ' + c.risk + ' risk signal.',
    'Micro-interazioni eliminate': 'Manual copy/paste of classifier JSON into Decision Packet shape.',
    'Scelta richiesta': 'Scrivi: 1 / 2 / 3',
    'Cosa NON viene fatto': 'No runtime, no Telegram send, no workflow mutation, no PM-34 unlock, no deploy/rollback, no secrets written, no automatic loop.',
    'Riferimento evento / provenienza': provenance,
    Risk: c.risk,
    Route: c.route,
    requires_human: c.requires_human,
    Confidence: c.confidence,
    'Classifier reason': c.reason
  };
}

const inp = $input.item.json;
const raw = inp.classifier_output;
let synthesized = false;
let c;

if (!isValidClassifier(raw)) {
  c = failClosed('fallback:malformed_or_incoherent_fixture');
  synthesized = true;
} else {
  c = { ...raw };
}

const noPacketEligible =
  !synthesized &&
  c.route === 'auto_allowed' &&
  c.requires_human === false &&
  c.confidence !== 'low';

if (noPacketEligible) {
  return {
    json: {
      fixture_id: inp.fixture_id,
      preview_status: 'NO_PACKET_NO_ACTION',
      packet_present: false,
      packet: null,
      effective_classifier: c,
      fail_closed_synthesized: false,
      fixture_only: true,
      test_only: true,
      no_runtime: true
    }
  };
}

let packetClassifier = { ...c };
if (c.confidence === 'low' || c.requires_human === true) {
  if (c.route !== 'blocked') {
    packetClassifier.route = 'human_gate';
  }
}
if (synthesized) {
  packetClassifier = { ...c };
}
if (packetClassifier.route === 'auto_allowed') {
  packetClassifier.route = 'human_gate';
}

const packet = buildPacket(packetClassifier, inp.event_context, inp.fixture_id);

return {
  json: {
    fixture_id: inp.fixture_id,
    preview_status: 'PACKET_PREVIEW',
    packet_present: true,
    packet,
    effective_classifier: packetClassifier,
    fail_closed_synthesized: synthesized,
    fixture_only: true,
    test_only: true,
    no_runtime: true
  }
};

// Read-only inspect / normalize preview output
const d = $input.item.json;
const ALLOWED = ['auto_allowed', 'human_gate', 'blocked'];

function routeCheck() {
  if (d.packet_present && d.packet && d.packet.Route) {
    return ALLOWED.includes(String(d.packet.Route));
  }
  if (d.effective_classifier && d.effective_classifier.route) {
    if (d.preview_status === 'NO_PACKET_NO_ACTION') {
      return d.effective_classifier.route === 'auto_allowed';
    }
    return ALLOWED.includes(String(d.effective_classifier.route));
  }
  return false;
}

return {
  json: {
    fixture_id: d.fixture_id,
    preview_status: d.preview_status,
    packet_present: d.packet_present,
    packet: d.packet,
    checks: {
      route_in_allowed_set: routeCheck(),
      no_send_performed: true,
      no_secret_placeholders_only: true,
      fixture_only: true,
      no_http_request_node_expected: true
    },
    fixture_only: true,
    test_only: true,
    no_runtime: true
  }
};
